export const gTeachyTvText_PokedudeSaysHello = "Hey, all you TRAINERS out there!\nHELLO, TRAINERS!\\p……… ……… ………\\pCome on, let me hear you!\nHELLO, TRAINERS!\\lIt's me, the POKé DUDE!\\p" as const;
export const gTeachyTvText_BattleScript1 = "Today, the POKé DUDE's here to\ntell you about how you can battle\\lPOKéMON!\\pSay you're out for a stroll when,\nsuddenly, a wild POKéMON appears!\\pIt's up to you to smartly use your\nPOKéMON and their moves to reduce\\lthe opponent's HP to nothing, and\\lclaim victory!\\pI'll show you how to do that in\nperson and for sure!\\pAll righty, here goes!\\pKeep your eyes glued to the super\nPOKé DUDE SHOW!" as const;
export const gTeachyTvText_BattleScript2 = "Well, did you get that?\\pEven if your own POKéMON's HP\nfalls to zero, and it becomes\\lunable to battle, not to worry!\\pJust take it to any POKéMON\nCENTER and heal it!\\pAll righty, be seeing you!\\pRemember, TRAINERS, a good deed\na day brings happiness to stay!" as const;
export const gTeachyTvText_StatusScript1 = "Today, the POKé DUDE's here to\ntell you about status problems!\\pStatus problems include poisoning,\nparalysis, sleep, burn…\\pThere are a couple others, but\nthey really are trouble.\\pGet any one, and your POKéMON\nmay become useless in battle.\\pYou know, it hurts the POKé DUDE\nto see a POKéMON suffer…\\pSo, what should you do if your\nPOKéMON gets a status problem?\\pWell, you've got me to show you!\\pAll righty, here goes!\\pKeep your eyes glued to the super\nPOKé DUDE SHOW!" as const;
export const gTeachyTvText_StatusScript2 = "Poisoning or paralysis don't go\naway after a battle.\\pIf a POKéMON is poisoned, it loses\nHP even while you're walking.\\pYou should heal POKéMON of these\nkinds of problems right away.\\pUse an item, or try to get to a\nPOKéMON CENTER for healing.\\pThat wasn't hard, was it?\nAll righty, be seeing you!\\pRemember, TRAINERS, a good deed\na day brings happiness to stay!" as const;
export const gTeachyTvText_MatchupsScript1 = "Does everyone know about type\nmatchups?\\pPOKéMON and their moves all\nbelong to certain types.\\pFor example, there are such types\nas GRASS and WATER.\\pYou need to consider the type of\nthe move used to attack…\\pAnd, the type of the POKéMON that\nis hit by that attack.\\pDepending on how those two types\nmatch up, the damage can change.\\pYou see, it depends on whether\nthe type matchup is good or bad.\\pIf you don't know how matchups\nwork, battles will be tough.\\pSo, let me demonstrate exactly\nwhat I mean.\\pAll righty, here goes!\\pKeep your eyes glued to the super\nPOKé DUDE SHOW!" as const;
export const gTeachyTvText_MatchupsScript2 = "Is it possible to launch an attack\nthat will inflict heavy damage?\\pDoes the opposing POKéMON pose\na threat to your POKéMON?\\pIs there any chance that it may\nhave disastrously tough moves?\\pWatch the type matchups to gain\nthe upper hand!\\pAll righty, be seeing you!\\pOh, for the COOL-type POKé DUDE,\nAWESOME-type kids like you match\\lup perfectly!\\pRemember, a good deed a day\nbrings happiness to stay!" as const;
export const gTeachyTvText_CatchingScript1 = "Today, the POKé DUDE's going to\nshow you how to catch POKéMON!\\pJust imagine… A groovy POKéMON\nsuddenly appearing in the wild!\\pOh, you want it!\nYou just can't help it!\\pOh, you have to catch it!\nYou gotta have it!\\pLet me show you how you can make\nit happen!\\pAll righty, here goes!\\pKeep your eyes glued to the super\nPOKé DUDE SHOW!" as const;
export const gTeachyTvText_CatchingScript2 = "If your first POKé BALL fails to\ncatch the POKéMON, don't give up!\\pKeep throwing POKé BALLS…\nIt's bound to work sometime!\\pAll righty, be seeing you!\\pRemember, TRAINERS, a good deed\na day brings happiness to stay!" as const;
export const gTeachyTvText_TMsScript1 = "Hey, everyone!\nDo you all have TMs?\\pA TM, Technical Machine, is an\namazingly great item!\\pIt teaches POKéMON a move that\nit may not learn when leveling up!\\pIsn't that just great? What a\nconvenient world we live in!\\pOpen the TM CASE and check out\nthe TMs you have.\\pYou can check them out in detail,\ntoo." as const;
export const gPokedudeText_TMTypes = "POKé DUDE: NORMAL, WATER, GRASS…\nTMs also come in types.\\pCheck the type and teach it to\na POKéMON that matches up well.\\pFor example, WATER PULSE is\nsuitable for WATER-type POKéMON.\\pBULLET SEED is a move that most\nGRASS-type POKéMON can learn.\\pThere's one other thing!" as const;
export const gPokedudeText_ReadTMDescription = "Don't just look at the type, read\nthe description, too.\\pIt will contain hints about what\nPOKéMON might learn the move.\\pFor example, take a move like\nFOCUS PUNCH.\\pIt doesn't sound like anything a\nbird or fish POKéMON can learn.\\pSo, try using it on POKéMON with\narms that can throw punches!" as const;
export const gTeachyTvText_TMsScript2 = "Wow, I talked a lot today!\nAll righty, be seeing you!\\pRemember, TRAINERS, a good deed\na day brings happiness to stay!" as const;
export const gTeachyTvText_RegisterScript1 = "A TRAINER's BAG has a bunch of\nnifty, convenient features!\\pTake stuff in the KEY ITEMS\nPOCKET, for instance.\\pYou can use a key item without\nopening the BAG every time.\\pFor example, let's pretend I have\na TEACHY TV in my BAG.\\pI can register it for instant use,\nand I'll show you how!\\pAll righty, here goes!\\pKeep your eyes glued to the sorta\nsuper POKé DUDE SHOW!" as const;
export const gTeachyTvText_RegisterScript2 = "And now, your TEACHY TV is\nregistered.\\pHow do you use it?\nWell, here's how it works.\\pOnce an item in the KEY ITEMS\nPOKCET is registered, you can use\\lit by pressing SELECT.\\pSo, you've given yourself\none-touch access to TEACHY TV.\\pAll it takes for you to see me is\npressing one button!\\pThat kind of attention is a little\nembarrassing!\\pAll righty, be seeing you!\\pRemember, TRAINERS, a good deed\na day brings happiness to stay!" as const;
